		content:
			"import type { RegistryItem } from '../../types'\n\nconst colorFieldMeta = {\n  name: 'color-field',\n  type: 'registry:ui',\n  group: 'inputs',\n  files: [\n    {\n      type: 'registry:ui',\n      path: 'ui/color-field/base.tsx',\n      target: 'ui/color-field.tsx',\n    },\n  ],\n  registryDependencies: ['field', 'input'],\n} satisfies RegistryItem\n\nexport default colorFieldMeta\n",
