			"'use client'\n\nimport type * as React from 'react'\nimport { XIcon } from 'lucide-react'\nimport { composeRenderProps } from 'react-aria-components/composeRenderProps'\nimport * as DialogPrimitive from 'react-aria-components/Dialog'\nimport * as TextPrimitives from 'react-aria-components/Text'\n\nimport { Button } from '../button'\nimport { ScrollFade } from '../scroll-fade'\n\nimport { useStyles } from './styles'\n\n// MARK: dialogStyles\n\n// MARK: Separator\n\ninterface DialogProps extends React.ComponentProps<\n  typeof DialogPrimitive.DialogTrigger\n> {}\n\nconst Dialog = (props: DialogProps) => {\n  return <DialogPrimitive.DialogTrigger {...props} />\n}\n\n// MARK: Separator\n\ninterface DialogContentProps extends React.ComponentProps<\n  typeof DialogPrimitive.Dialog\n> {\n  showCloseButton?: boolean\n}\n\nconst DialogContent = ({\n  className,\n  children,\n  showCloseButton = false,\n  ...props\n}: DialogContentProps) => {\n  const { content, closeButton } = useStyles()()\n  return (\n    <DialogPrimitive.Dialog\n      data-slot=\"dialog-content\"\n      className={content({ className })}\n      {...props}\n    >\n      {composeRenderProps(children, (children) => (\n        <>\n          {children}\n          {showCloseButton && (\n            <Button\n              slot=\"close\"\n              variant=\"quiet\"\n              size=\"sm\"\n              isIconOnly\n              aria-label=\"Close\"\n              className={closeButton()}\n            >\n              <XIcon />\n            </Button>\n          )}\n        </>\n      ))}\n    </DialogPrimitive.Dialog>\n  )\n}\n\n// MARK: Separator\n\ninterface DialogHeaderProps extends React.ComponentProps<'header'> {}\n\nconst DialogHeader = ({ className, ...props }: DialogHeaderProps) => {\n  const { header } = useStyles()()\n  return (\n    <header\n      data-slot=\"dialog-header\"\n      className={header({ className })}\n      {...props}\n    />\n  )\n}\n\n// MARK: Separator\n\ninterface DialogTitleProps extends React.ComponentProps<\n  typeof DialogPrimitive.Heading\n> {}\n\nconst DialogTitle = ({ className, ...props }: DialogTitleProps) => {\n  const { title } = useStyles()()\n  return (\n    <DialogPrimitive.Heading\n      slot=\"title\"\n      data-slot=\"dialog-heading\"\n      className={title({ className })}\n      {...props}\n    />\n  )\n}\n\n// MARK: Separator\n\ninterface DialogDescriptionProps extends Omit<\n  React.ComponentProps<typeof TextPrimitives.Text>,\n  'slot'\n> {}\n\nconst DialogDescription = ({ className, ...props }: DialogDescriptionProps) => {\n  const { description } = useStyles()()\n  return (\n    <TextPrimitives.Text\n      data-slot=\"dialog-description\"\n      className={description({ className })}\n      {...props}\n    />\n  )\n}\n\n// MARK: Separator\n\ninterface DialogBodyProps extends React.ComponentProps<'div'> {\n  scrollFade?: boolean\n}\n\nconst DialogBody = ({\n  className,\n  scrollFade = false,\n  ...props\n}: DialogBodyProps) => {\n  const { body } = useStyles()()\n  const ElementType = scrollFade ? ScrollFade : 'div'\n\n  return (\n    <ElementType\n      data-slot=\"dialog-body\"\n      className={body({ className })}\n      {...props}\n    />\n  )\n}\n\n// MARK: Separator\n\ntype DialogInsetProps = React.ComponentProps<'div'>\n\nconst DialogInset = (props: DialogInsetProps) => {\n  return <div data-slot=\"dialog-inset\" {...props} />\n}\n\n// MARK: Separator\n\ntype DialogFooterProps = React.ComponentProps<'footer'>\n\nconst DialogFooter = ({ className, ...props }: DialogFooterProps) => {\n  const { footer } = useStyles()()\n  return (\n    <footer\n      data-slot=\"dialog-footer\"\n      className={footer({ className })}\n      {...props}\n    />\n  )\n}\n\n// MARK: Separator\n\nexport type {\n  DialogBodyProps,\n  DialogContentProps,\n  DialogDescriptionProps,\n  DialogFooterProps,\n  DialogHeaderProps,\n  DialogInsetProps,\n  DialogProps,\n  DialogTitleProps,\n}\nexport {\n  Dialog,\n  DialogBody,\n  DialogContent,\n  DialogDescription,\n  DialogFooter,\n  DialogHeader,\n  DialogInset,\n  DialogTitle,\n}\n",
